mapper.select:
SELECT a.id, a.house_id, a.item_code, a.item_group, a.standard_id, a.org_id, b.room_num, c.user_name, c.phone, c.user_id, d.name, d.standard_price, d.money_formula, d.step_type, e.item_name FROM pr_house_expense a LEFT JOIN pr_house b ON a.house_id = b.id LEFT JOIN pr_user_house c ON c.house_id = b.id AND c.del_flag = '0' LEFT JOIN pr_standard d ON a.standard_id = d.id LEFT JOIN pr_expense_item e ON a.item_group = e.item_group AND a.item_code = e.item_code WHERE b.del_flag = '0'
AND a.org_id = #{orgId} AND e.org_id = #{orgId}
AND b.building_id = #{buildingId}
AND b.unit_code = #{unitCode}
AND a.item_group = #{itemGroup}
AND a.item_code = #{itemCode}
AND (b.room_num LIKE CONCAT('%', #{search}, '%') OR c.phone LIKE CONCAT('%', #{search}, '%'))
GROUP BY b.building_name, b.room_num, a.item_group, a.item_code ORDER BY b.room_num, a.item_group, a.item_code

SELECT id, room_num,
       #{itemGroup} AS item_group,
       #{itemCode} AS item_code,
       #{itemName} AS item_name
FROM pr_house
WHERE id NOT IN (
    SELECT a.id FROM pr_house a
    LEFT JOIN pr_house_expense c ON c.house_id = a.id
    WHERE a.del_flag = '0' AND a.org_id = #{orgId} AND c.org_id = #{orgId}
      AND c.item_group = #{itemGroup} AND c.item_code = #{itemCode}
)
AND org_id = #{orgId} AND del_flag = '0'

    AND building_id = #{buildingId}


    AND unit_code = #{unitCode}


    AND room_num = #{search}
